<template>
    <div>
        <!-- 面包屑 -->
        <el-breadcrumb separator-class="el-icon-arrow-right">
            <el-breadcrumb-item :to="{ path: '/' }">首页</el-breadcrumb-item>
            <el-breadcrumb-item>权限管理</el-breadcrumb-item>
            <el-breadcrumb-item>用户列表</el-breadcrumb-item>
        </el-breadcrumb>
        <!-- 卡片 -->
        <el-card class="box-card">
            <el-button type="primary" @click="dialogVisible = true">添加角色</el-button>
        </el-card>
        <!-- 表格 -->

        <template>
            <el-table :data="tableData" style="width: 100%">
                <el-table-column type="expand">

                </el-table-column>
                <el-table-column label="#" type="index">
                </el-table-column>
                <el-table-column label="角色名称" prop="roleName">
                </el-table-column>
                <el-table-column label="角色描述" prop="roleDesc">
                </el-table-column>
                <el-table-column label="操作">
                    <template slot-scope="scope">
                        <el-button type="primary" @click="jiaoEdit(scope.row)" icon="el-icon-edit" size="mini">编辑</el-button>

                        <el-button type="danger"  @click="open(scope.row.id)" icon="el-icon-delete" size="mini">删除</el-button>

                        <el-button type="warning" icon="el-icon-star-off" size="mini">分配权限</el-button>
                    </template>
                </el-table-column>
            </el-table>
        </template>

        <!-- 弹出框添加 -->
        <el-dialog title="添加角色" :visible.sync="dialogVisible" width="30%">
            <!-- <span>这是一段信息</span> -->
            <!-- from表单 -->
            <el-form :model="ruleForm" status-icon :rules="rules" ref="ruleForm" label-width="100px"
                class="demo-ruleForm">
                <el-form-item label="角色名称" prop="roleName">
                    <el-input type="text" v-model="ruleForm.roleName" autocomplete="off"></el-input>
                </el-form-item>

                <el-form-item label="角色描述" prop="roleDesc">
                    <el-input type="text" v-model="ruleForm.roleDesc" autocomplete="off"></el-input>
                </el-form-item>
            </el-form>
            <span slot="footer" class="dialog-footer">
                <el-button @click="dialogVisible = false">取 消</el-button>
                <el-button type="primary" @click="queT()">确 定</el-button>
            </span>
        </el-dialog>
        <!-- 弹出框修改 -->
        <el-dialog
            title="提示"
            :visible.sync="edit"
            width="30%">
            <!-- <span>这是一段信息</span> -->
            <!-- from表单 -->
            <el-form :model="fromedit" status-icon   ref="ruleForm" label-width="100px"
                class="demo-ruleForm">
                <el-form-item label="角色名称" prop="roleName">
                    <el-input type="text" v-model="fromedit.roleName" autocomplete="off"></el-input>
                </el-form-item>

                <el-form-item label="角色描述" prop="roleDesc">
                    <el-input type="text" v-model="fromedit.roleDesc" autocomplete="off"></el-input>
                </el-form-item>
            </el-form>



            <span slot="footer" class="dialog-footer">
                <el-button @click="dialogVisible = false">取 消</el-button>
                <el-button type="primary" @click="queEdit()">确 定</el-button>
            </span>
        </el-dialog>

    </div>
</template>

<script>
    export default {
        data() {
            var validatePass = (rule, value, callback) => {
                if (value === '') {
                    callback(new Error('请输入角色名称'));
                } else {
                    if (this.ruleForm.checkPass !== '') {
                        this.$refs.ruleForm.validateField('checkPass');
                    }
                    callback();
                }
            };
            var roleDesc = (rule, value, callback) => {
                if (value === '') {
                    callback(new Error('请输入角色描述'));
                } else {
                    if (this.ruleForm.checkPass !== '') {
                        this.$refs.ruleForm.validateField('checkPass');
                    }
                    callback();
                }
            };
            return {
                tableData: [],    //角色数据
                dialogVisible: false, //添加框隐藏显示
                edit:false,
                ruleForm: {
                    roleName: '',
                    roleDesc: ''
                },
                rules: {
                    roleName: [
                        { validator: validatePass, trigger: 'blur' }
                    ],
                    roleDesc: [
                        { validator: roleDesc, trigger: 'blur' }
                    ]
                },
                fromedit:{
                    roleName:'',
                    roleDesc:''
                }
            };
        },
        created() {

        },
        mounted() {
            this.ajax()
        },
        methods: {
            // 获取角色列表
            ajax() {
                this.$http.get('/roles').then(res => {
                    this.tableData = res.data.data
                    // console.log(this.tableData)
                })
            },
            // 添加角色
            queT() {
                this.$http.post('/roles', {
                    roleName: this.ruleForm.roleName,
                    roleDesc: this.ruleForm.roleDesc
                }).then(res => {
                    console.log(res)
                    if (res.data.meta.msg == "创建成功") {
                        this.dialogVisible = false
                        this.$message({
                            type: 'success',
                            message: res.data.meta.msg,
                            duration: 1000
                        });
                        this.ajax()
                    }
                })
            },
            // 删除
            open(i) {
                // console.log(i)
                this.$confirm('此操作将永久删除该角色, 是否继续?', '提示', {
                    confirmButtonText: '确定',
                    cancelButtonText: '取消',
                    type: 'warning'
                }).then(() => {
                    this.$http.delete('/roles/'+i).then(res=>{
                        console.log(res)
                        if(res.data.meta.msg=='删除成功'){
                            this.$message({
                                type: 'success',
                                message: '删除成功!'
                            });
                            this.ajax()
                        }
                    })
                })
            },
            // 点击编辑用户
            jiaoEdit(i){
                // console.log(i)
                this.fromedit=i
                this.edit=true
            },
            // 点击确定编辑用户
            queEdit(){
                this.$http.put('/roles/'+this.fromedit.id,{
                    roleName:this.fromedit.roleName,
                    roleDesc:this.fromedit.roleDesc
                }).then(res=>{
                    console.log(res)
                    if(res.data.meta.msg=="获取成功"){
                        this.$message({
                                type: 'success',
                                message: res.data.meta.msg,
                                duration: 1000
                        });
                        this.edit=false
                    this.ajax()

                    }
                })
            }
        }
    };
</script>

<style scoped>
    .box-card {
        margin-top: 10px;
    }
</style>